19	// ExecutionsStateProvider is the optional sub-interface a StateProvider may
20	// implement to back the executions/execution/executionToolCalls queries.
21	// Kept separate from StateProvider so test stubs that don't need executions
22	// continue to compile.
23	type ExecutionsStateProvider interface {
24		GetExecutionsGraphQL(projectID string, filter ExecutionFilter) []*Execution
25		GetExecutionGraphQL(id string) (*Execution, bool)
26		GetExecutionToolCallsGraphQL(id string) []*ExecutionToolCall
27	}
