115	func emptyExecutionConnection() *ExecutionConnection {
116		return &ExecutionConnection{Edges: []*ExecutionEdge{}, PageInfo: &PageInfo{}, TotalCount: 0}
117	}
118	
119	func emptyToolCallConnection() *ExecutionToolCallConnection {
120		return &ExecutionToolCallConnection{Edges: []*ExecutionToolCallEdge{}, PageInfo: &PageInfo{}, TotalCount: 0}
121	}
