10	// ExecLogProvider fetches execution run logs by run ID.
11	// Implementations should return a non-nil error when the run is not yet
12	// available so the resolver can retry.
13	type ExecLogProvider interface {
14		GetExecLog(runID string) (stdout, stderr string, err error)
15	}
16	
17	// CoordinatorMetricsSnap is a point-in-time snapshot of land-coordinator
18	// metrics. Defined here so the server package can satisfy the
19	// CoordinatorMetricsProvider interface without an import cycle.
20	type CoordinatorMetricsSnap struct {
21		Landed          int64
22		Preserved       int64
23		Failed          int64
24		PushFailed      int64
25		TotalDurationMS int64
26		TotalCommits    int64
27	}
28	
29	// CoordinatorMetricsProvider can fetch a coordinator metrics snapshot for a
30	// given project root. Returns nil if no coordinator has been started for that
31	// project yet.
32	type CoordinatorMetricsProvider interface {
33		GetCoordinatorMetrics(projectRoot string) *CoordinatorMetricsSnap
34	}
35	
36	// ExecutionEvidence is the resolver for the executionEvidence subscription.
37	// It polls ExecLogProvider until the run log is available, then streams each
38	// stdout and stderr line as a separate ExecutionEvent and closes the channel.
39	func (r *subscriptionResolver) ExecutionEvidence(ctx context.Context, runID string) (<-chan *ExecutionEvent, error) {
40		if r.ExecLogs == nil {
41			return nil, fmt.Errorf("subscription not available: execution log provider not configured")
42		}
43	
44		out := make(chan *ExecutionEvent, 32)
45		go func() {
46			defer close(out)
47			ticker := time.NewTicker(500 * time.Millisecond)
48			defer ticker.Stop()
49			for {
50				stdout, stderr, err := r.ExecLogs.GetExecLog(runID)
51				if err == nil {
52					now := time.Now().UTC().Format(time.RFC3339)
53					seq := 0
54					emit := func(stream, line string) bool {
55						evt := &ExecutionEvent{
56							EventID:   fmt.Sprintf("%s-%d", runID, seq),
57							RunID:     runID,
58							Stream:    stream,
59							Line:      line,
60							Timestamp: now,
61						}
62						seq++
63						select {
64						case out <- evt:
65							return true
66						case <-ctx.Done():
67							return false
68						}
69					}
70					for _, line := range splitLines(stdout) {
71						if !emit("stdout", line) {
72							return
73						}
74					}
75					for _, line := range splitLines(stderr) {
76						if !emit("stderr", line) {
77							return
78						}
79					}
80					return
81				}
82				select {
83				case <-ctx.Done():
84					return
85				case <-ticker.C:
86				}
87			}
88		}()
89		return out, nil
90	}
91	
92	// CoordinatorMetrics is the resolver for the coordinatorMetrics subscription.
93	// It polls CoordinatorMetricsProvider once per MetricsPollInterval (default 1s)
94	// and emits a CoordinatorMetricsUpdate whenever the snapshot for projectRoot
95	// changes.
96	func (r *subscriptionResolver) CoordinatorMetrics(ctx context.Context, projectRoot string) (<-chan *CoordinatorMetricsUpdate, error) {
97		if r.CoordMetrics == nil {
98			return nil, fmt.Errorf("subscription not available: coordinator metrics provider not configured")
99		}
100	
101		interval := r.MetricsPollInterval
102		if interval <= 0 {
103			interval = time.Second
104		}
105	
106		out := make(chan *CoordinatorMetricsUpdate, 16)
107		go func() {
108			defer close(out)
109			var last CoordinatorMetricsSnap
110			hasPrev := false
111			seq := 0
112			ticker := time.NewTicker(interval)
113			defer ticker.Stop()
114			for {
115				select {
116				case <-ctx.Done():
117					return
118				case <-ticker.C:
119					snap := r.CoordMetrics.GetCoordinatorMetrics(projectRoot)
120					if snap == nil {
121						continue
122					}
123					if hasPrev && *snap == last {
124						continue
125					}
126					hasPrev = true
127					last = *snap
128					seq++
129					ts := time.Now().UTC().Format(time.RFC3339)
130					update := &CoordinatorMetricsUpdate{
131						UpdateID:        fmt.Sprintf("%s-update-%d", projectRoot, seq),
132						ProjectRoot:     projectRoot,
133						Timestamp:       ts,
134						Landed:          int(snap.Landed),
135						Preserved:       int(snap.Preserved),
136						Failed:          int(snap.Failed),
137						PushFailed:      int(snap.PushFailed),
138						TotalDurationMs: int(snap.TotalDurationMS),
139						TotalCommits:    int(snap.TotalCommits),
140					}
141					select {
142					case out <- update:
143					case <-ctx.Done():
144						return
145					}
146				}
147			}
148		}()
149		return out, nil
150	}
