15	// executionsTestProvider extends a base testStateProvider with the optional
16	// ExecutionsStateProvider methods so the executions/execution/executionToolCalls
17	// resolvers route to in-memory data.
18	type executionsTestProvider struct {
19		*testStateProvider
20		all   []*ddxgraphql.Execution
21		calls map[string][]*ddxgraphql.ExecutionToolCall
22	}
23	
24	func (p *executionsTestProvider) GetExecutionsGraphQL(projectID string, filter ddxgraphql.ExecutionFilter) []*ddxgraphql.Execution {
25		if projectID == "" {
26			return nil
27		}
28		out := make([]*ddxgraphql.Execution, 0, len(p.all))
29		for _, e := range p.all {
30			if e.ProjectID != projectID {
31				continue
32			}
33			if filter.BeadID != "" && (e.BeadID == nil || *e.BeadID != filter.BeadID) {
34				continue
35			}
36			if filter.Verdict != "" && (e.Verdict == nil || !strings.EqualFold(*e.Verdict, filter.Verdict)) {
37				continue
38			}
39			if filter.Harness != "" && (e.Harness == nil || *e.Harness != filter.Harness) {
40				continue
41			}
42			out = append(out, e)
43		}
44		return out
45	}
46	
47	func (p *executionsTestProvider) GetExecutionGraphQL(id string) (*ddxgraphql.Execution, bool) {
48		for _, e := range p.all {
49			if e.ID == id {
50				return e, true
51			}
52		}
53		return nil, false
54	}
