60	func makeExecution(projectID, id, beadID, harness, verdict string) *ddxgraphql.Execution {
61		bID := beadID
62		h := harness
63		v := verdict
64		dur := 1500
65		cost := 0.012
66		tokens := 880
67		prompt := fmt.Sprintf("prompt body for %s", id)
68		manifest := fmt.Sprintf(`{"bead_id":"%s","attempt_id":"%s"}`, beadID, id)
69		result := fmt.Sprintf(`{"verdict":"%s","rationale":"reason for %s"}`, verdict, id)
70		return &ddxgraphql.Execution{
71			ID:         id,
72			ProjectID:  projectID,
73			BeadID:     &bID,
74			Harness:    &h,
75			Verdict:    &v,
76			CreatedAt:  time.Now().UTC().Format(time.RFC3339),
77			BundlePath: ".ddx/executions/" + id,
78			DurationMs: &dur,
79			CostUsd:    &cost,
80			Tokens:     &tokens,
81			Prompt:     &prompt,
82			Manifest:   &manifest,
83			Result:     &result,
84		}
85	}
