87	func writeExecutionFixture(t *testing.T, projectRoot, id, bead string) {
88		t.Helper()
89		dir := filepath.Join(projectRoot, ".ddx", "executions", id)
90		if err := os.MkdirAll(dir, 0o755); err != nil {
91			t.Fatal(err)
92		}
93		manifest := map[string]any{"attempt_id": id, "bead_id": bead, "created_at": time.Now().UTC().Format(time.RFC3339)}
94		mb, _ := json.Marshal(manifest)
95		_ = os.WriteFile(filepath.Join(dir, "manifest.json"), mb, 0o644)
96		_ = os.WriteFile(filepath.Join(dir, "result.json"), []byte(`{"verdict":"PASS"}`), 0o644)
97		_ = os.WriteFile(filepath.Join(dir, "prompt.md"), []byte("hi"), 0o644)
98	}
