77	// loadExecutionBundle reads and merges manifest.json and result.json from a
78	// bundle directory. The two are complementary — manifest has the request,
79	// result has the outcome — so the merged record is the canonical one.
80	func loadExecutionBundle(projectID, projectRoot, bundleDirAbs, bundleID string) *ddxgraphql.Execution {
81		manifest := executionBundleManifest{}
82		if data, err := os.ReadFile(filepath.Join(bundleDirAbs, "manifest.json")); err == nil {
83			_ = json.Unmarshal(data, &manifest)
84		}
85		result := executionBundleResult{}
86		if data, err := os.ReadFile(filepath.Join(bundleDirAbs, "result.json")); err == nil {
87			_ = json.Unmarshal(data, &result)
88		}
89		bundleRel := filepath.ToSlash(filepath.Join(agent.ExecuteBeadArtifactDir, bundleID))
90	
91		exec := &ddxgraphql.Execution{
92			ID:         bundleID,
93			ProjectID:  projectID,
94			BundlePath: bundleRel,
95		}
96		// Created-at: prefer manifest.created_at; fall back to bundle directory
97		// timestamp prefix (e.g. 20260423T053812).
98		if manifest.CreatedAt != "" {
99			exec.CreatedAt = normalizeISOTime(manifest.CreatedAt)
100		} else if t, ok := parseBundleTimestamp(bundleID); ok {
101			exec.CreatedAt = t.UTC().Format(time.RFC3339)
102		} else if info, err := os.Stat(bundleDirAbs); err == nil {
103			exec.CreatedAt = info.ModTime().UTC().Format(time.RFC3339)
104		}
105	
106		// Bead info — prefer richer manifest, then either source's bead_id.
107		beadID := firstNonEmptyStr(manifest.BeadID, manifest.Bead.ID, result.BeadID)
108		if beadID != "" {
109			exec.BeadID = &beadID
110		}
111		if manifest.Bead.Title != "" {
112			title := manifest.Bead.Title
113			exec.BeadTitle = &title
114		}
115	
116		// Harness / model — manifest.requested takes precedence (user intent),
117		// else result, else manifest top-level (terse schema).
118		harness := firstNonEmptyStr(manifest.Requested.Harness, result.Harness, manifest.Harness)
119		if harness != "" {
120			exec.Harness = &harness
121		}
122		model := firstNonEmptyStr(manifest.Requested.Model, result.Model, manifest.Model)
123		if model != "" {
124			exec.Model = &model
125		}
126	
127		// Verdict — manifest.verdict (terse schema) wins, else result.verdict,
128		// else result.outcome / status.
129		verdict := firstNonEmptyStr(manifest.Verdict, result.Verdict, result.Outcome, result.Status)
130		if verdict != "" {
131			exec.Verdict = &verdict
132		}
133		if result.Status != "" {
134			s := result.Status
135			exec.Status = &s
136		}
137	
138		// Rationale — prefer the explicit rationale field, else no_changes
139		// rationale, else generic detail.
140		rationale := firstNonEmptyStr(result.Rationale, result.NoChangesRationale, result.Detail)
141		if rationale != "" {
142			exec.Rationale = &rationale
143		}
144	
145		if result.SessionID != "" {
146			s := result.SessionID
147			exec.SessionID = &s
148		}
149		workerID := firstNonEmptyStr(manifest.WorkerID, result.WorkerID)
150		if workerID != "" {
151			exec.WorkerID = &workerID
152		}
153		if result.StartedAt != "" {
154			s := normalizeISOTime(result.StartedAt)
155			exec.StartedAt = &s
156		}
157		if result.FinishedAt != "" {
158			s := normalizeISOTime(result.FinishedAt)
159			exec.FinishedAt = &s
160		}
161		if result.DurationMS > 0 {
162			d := result.DurationMS
163			exec.DurationMs = &d
164		}
165		if result.CostUSD != 0 {
166			c := result.CostUSD
167			exec.CostUsd = &c
168		}
169		if result.Tokens > 0 {
170			t := result.Tokens
171			exec.Tokens = &t
172		}
173		ec := result.ExitCode
174		exec.ExitCode = &ec
175		baseRev := firstNonEmptyStr(manifest.BaseRev, result.BaseRev)
176		if baseRev != "" {
177			exec.BaseRev = &baseRev
178		}
179		resultRev := firstNonEmptyStr(manifest.ResultRev, result.ResultRev)
180		if resultRev != "" {
181			exec.ResultRev = &resultRev
182		}
183	
184		// Path pointers — prefer manifest.paths if populated, else default
185		// names within the bundle dir.
186		promptRel := firstNonEmptyStr(manifest.Paths.Prompt, filepath.ToSlash(filepath.Join(bundleRel, "prompt.md")))
187		exec.PromptPath = &promptRel
188		manifestRel := firstNonEmptyStr(manifest.Paths.Manifest, filepath.ToSlash(filepath.Join(bundleRel, "manifest.json")))
189		exec.ManifestPath = &manifestRel
190		resultRel := firstNonEmptyStr(manifest.Paths.Result, filepath.ToSlash(filepath.Join(bundleRel, "result.json")))
191		exec.ResultPath = &resultRel
192	
193		// Agent-log path — prefer explicit pointer, else the conventional
194		// per-session file under .ddx/agent-logs/.
195		if result.AgentLogPath != "" {
196			s := filepath.ToSlash(result.AgentLogPath)
197			exec.AgentLogPath = &s
198		} else if result.SessionID != "" {
199			s := filepath.ToSlash(filepath.Join(".ddx/agent-logs", "agent-"+result.SessionID+".jsonl"))
200			exec.AgentLogPath = &s
201		}
202		return exec
203	}
