255	// looksLikeBundleID checks for the YYYYMMDDTHHMMSS-<hex> shape used by
256	// execute-bead, plus a permissive fallback that accepts any non-special name.
257	// It rejects the special "mirror-index.jsonl" file and other reserved names.
258	func looksLikeBundleID(name string) bool {
259		if name == "" || strings.HasPrefix(name, ".") {
260			return false
261		}
262		if strings.Contains(name, ".jsonl") || strings.Contains(name, ".json") {
263			return false
264		}
265		return true
266	}
267	
268	func parseBundleTimestamp(name string) (time.Time, bool) {
269		idx := strings.IndexByte(name, '-')
270		if idx <= 0 {
271			return time.Time{}, false
272		}
273		stamp := name[:idx]
274		if t, err := time.Parse("20060102T150405", stamp); err == nil {
275			return t, true
276		}
277		return time.Time{}, false
278	}
279	
280	func normalizeISOTime(s string) string {
281		if s == "" {
282			return ""
283		}
284		if t, err := time.Parse(time.RFC3339Nano, s); err == nil {
285			return t.UTC().Format(time.RFC3339)
286		}
287		if t, err := time.Parse(time.RFC3339, s); err == nil {
288			return t.UTC().Format(time.RFC3339)
289		}
290		return s
291	}
