315	func applyExecutionFilter(in []*ddxgraphql.Execution, filter ddxgraphql.ExecutionFilter) []*ddxgraphql.Execution {
316		if len(in) == 0 {
317			return in
318		}
319		if filter.BeadID == "" && filter.Verdict == "" && filter.Harness == "" && filter.Search == "" && filter.Since == nil && filter.Until == nil {
320			return in
321		}
322		q := strings.ToLower(filter.Search)
323		out := in[:0:0]
324		for _, e := range in {
325			if filter.BeadID != "" {
326				if e.BeadID == nil || *e.BeadID != filter.BeadID {
327					continue
328				}
329			}
330			if filter.Verdict != "" {
331				if e.Verdict == nil || !strings.EqualFold(*e.Verdict, filter.Verdict) {
332					continue
333				}
334			}
335			if filter.Harness != "" {
336				if e.Harness == nil || *e.Harness != filter.Harness {
337					continue
338				}
339			}
340			if filter.Since != nil {
341				if t, err := time.Parse(time.RFC3339, e.CreatedAt); err == nil {
342					if t.Before(*filter.Since) {
343						continue
344					}
345				}
346			}
347			if filter.Until != nil {
348				if t, err := time.Parse(time.RFC3339, e.CreatedAt); err == nil {
349					if !t.Before(*filter.Until) {
350						continue
351					}
352				}
353			}
354			if q != "" {
355				matched := false
356				if e.BeadTitle != nil && strings.Contains(strings.ToLower(*e.BeadTitle), q) {
357					matched = true
358				}
359				if !matched && e.BeadID != nil && strings.Contains(strings.ToLower(*e.BeadID), q) {
360					matched = true
361				}
362				if !matched {
363					continue
364				}
365			}
366			out = append(out, e)
367		}
368		return out
369	}
