371	// GetExecutionGraphQL implements ExecutionsStateProvider.
372	func (s *ServerState) GetExecutionGraphQL(id string) (*ddxgraphql.Execution, bool) {
373		if id == "" {
374			return nil, false
375		}
376		for _, proj := range s.GetProjects(false) {
377			bundleDirAbs := filepath.Join(proj.Path, agent.ExecuteBeadArtifactDir, id)
378			if info, err := os.Stat(bundleDirAbs); err != nil || !info.IsDir() {
379				continue
380			}
381			exec := loadExecutionBundleDetail(proj.ID, proj.Path, bundleDirAbs, id)
382			if exec != nil {
383				return exec, true
384			}
385		}
386		return nil, false
387	}
