405	// GetExecutionToolCallsGraphQL implements ExecutionsStateProvider.
406	//
407	// Reads the agent-log file for the given execution and returns one
408	// ExecutionToolCall per recognized tool_call/tool_use frame.
409	func (s *ServerState) GetExecutionToolCallsGraphQL(id string) []*ddxgraphql.ExecutionToolCall {
410		if id == "" {
411			return nil
412		}
413		for _, proj := range s.GetProjects(false) {
414			bundleDirAbs := filepath.Join(proj.Path, agent.ExecuteBeadArtifactDir, id)
415			if info, err := os.Stat(bundleDirAbs); err != nil || !info.IsDir() {
416				continue
417			}
418			// Find the agent log path: prefer manifest pointer, else session id
419			// convention, else look for embedded/agent-*.jsonl in the bundle.
420			exec := loadExecutionBundle(proj.ID, proj.Path, bundleDirAbs, id)
421			if exec == nil {
422				return nil
423			}
424			var paths []string
425			if exec.AgentLogPath != nil {
426				abs := *exec.AgentLogPath
427				if !filepath.IsAbs(abs) {
428					abs = filepath.Join(proj.Path, abs)
429				}
430				paths = append(paths, abs)
431			}
432			// Also scan the bundle's embedded/ directory for agent-*.jsonl.
433			embedded := filepath.Join(bundleDirAbs, "embedded")
434			if entries, err := os.ReadDir(embedded); err == nil {
435				for _, e := range entries {
436					if e.IsDir() {
437						continue
438					}
439					n := e.Name()
440					if strings.HasPrefix(n, "agent-") && strings.HasSuffix(n, ".jsonl") {
441						paths = append(paths, filepath.Join(embedded, n))
442					}
443				}
444			}
445			for _, p := range paths {
446				if calls := readToolCallsFile(p); len(calls) > 0 {
447					return calls
448				}
449			}
450			return nil
451		}
452		return nil
453	}
454	
455	func readToolCallsFile(path string) []*ddxgraphql.ExecutionToolCall {
456		f, err := os.Open(path)
457		if err != nil {
458			return nil
459		}
460		defer f.Close()
461		var calls []*ddxgraphql.ExecutionToolCall
462		scanner := bufio.NewScanner(f)
463		scanner.Buffer(make([]byte, 64*1024), 4*1024*1024)
464		seq := 0
465		for scanner.Scan() {
466			line := bytes.TrimSpace(scanner.Bytes())
467			if len(line) == 0 || line[0] != '{' {
468				continue
469			}
470			var frame agentLogFrame
471			if err := json.Unmarshal(line, &frame); err != nil {
472				continue
473			}
474			kind := frame.Kind
475			if kind == "" {
476				kind = frame.Type
477			}
478			if !isToolCallKind(kind) {
479				continue
480			}
481			name := frame.Name
482			if name == "" {
483				name = frame.Tool
484			}
485			if name == "" {
486				continue
487			}
488			ts := frame.TS
489			if ts == "" {
490				ts = frame.Time
491			}
492			input := string(firstNonEmptyRaw(frame.Inputs, frame.Input))
493			output := string(firstNonEmptyRaw(frame.Output, frame.Result))
494			const maxOut = 64 * 1024
495			truncated := false
496			if len(output) > maxOut {
497				output = output[:maxOut]
498				truncated = true
499			}
500			call := &ddxgraphql.ExecutionToolCall{
501				ID:   formatToolCallID(seq),
502				Name: name,
503				Seq:  seq,
504			}
505			if ts != "" {
506				s := normalizeISOTime(ts)
507				call.Ts = &s
508			}
509			if input != "" {
510				call.Inputs = &input
511			}
512			if output != "" {
513				call.Output = &output
514			}
515			if truncated {
516				t := true
517				call.Truncated = &t
518			}
519			calls = append(calls, call)
520			seq++
521		}
522		return calls
523	}
524	
525	func isToolCallKind(kind string) bool {
526		switch strings.ToLower(kind) {
527		case "tool_call", "tool_use":
528			return true
529		}
530		return false
531	}
532	
533	func firstNonEmptyRaw(values ...json.RawMessage) json.RawMessage {
534		for _, v := range values {
535			if len(v) > 0 && string(v) != "null" {
536				return v
537			}
538		}
539		return nil
540	}
541	
542	func formatToolCallID(seq int) string {
543		return "tc-" + strconv.Itoa(seq)
544	}
