142	// BeadReopen is the resolver for the beadReopen mutation.
143	func (r *mutationResolver) BeadReopen(ctx context.Context, id string) (*Bead, error) {
144		if r.WorkingDir == "" {
145			return nil, fmt.Errorf("working directory not configured")
146		}
147	
148		store := r.beadStore()
149		err := store.Update(id, func(b *bead.Bead) {
150			b.Status = bead.StatusOpen
151			b.Owner = ""
152		})
153		if err != nil {
154			return nil, err
155		}
156	
157		b, err := store.Get(id)
158		if err != nil {
159			return nil, err
160		}
161		return beadModelFromBead(b), nil
162	}
