164	// BeadClose is the resolver for the beadClose field.
165	func (r *mutationResolver) BeadClose(ctx context.Context, id string, reason *string) (*Bead, error) {
166		if r.WorkingDir == "" {
167			return nil, fmt.Errorf("working directory not configured")
168		}
169		store := r.beadStore()
170		if err := store.Close(id); err != nil {
171			return nil, err
172		}
173		if reason != nil && strings.TrimSpace(*reason) != "" {
174			_ = store.AppendEvent(id, bead.BeadEvent{
175				Kind:    "summary",
176				Summary: "closed: " + strings.TrimSpace(*reason),
177			})
178		}
179		b, err := store.Get(id)
180		if err != nil {
181			return nil, err
182		}
183		return beadModelFromBead(b), nil
184	}
