186	// DocumentWrite is the resolver for the documentWrite mutation.
187	func (r *mutationResolver) DocumentWrite(ctx context.Context, path string, content string) (*Document, error) {
188		if r.WorkingDir == "" {
189			return nil, fmt.Errorf("working directory not configured")
190		}
191		if path == "" {
192			return nil, fmt.Errorf("path is required")
193		}
194	
195		cleaned := filepath.Clean(path)
196		if strings.Contains(cleaned, "..") {
197			return nil, fmt.Errorf("invalid path: must not contain ..")
198		}
199	
200		libPath, err := r.libraryPath()
201		if err != nil {
202			return nil, err
203		}
204	
205		fullPath := filepath.Join(libPath, cleaned)
206		if err := os.MkdirAll(filepath.Dir(fullPath), 0o755); err != nil {
207			return nil, fmt.Errorf("creating directory: %w", err)
208		}
209		if err := os.WriteFile(fullPath, []byte(content), 0o644); err != nil {
210			return nil, fmt.Errorf("writing document: %w", err)
211		}
212	
213		// Rebuild graph to pick up the newly written file and return the document.
214		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
215		if err != nil {
216			// File was written; return a minimal document rather than failing.
217			return &Document{
218				ID:         cleaned,
219				Path:       cleaned,
220				DependsOn:  []string{},
221				Inputs:     []string{},
222				Dependents: []string{},
223			}, nil
224		}
225	
226		// Look up the document by its cleaned path.
227		if id, ok := graph.PathToID[cleaned]; ok {
228			if doc, ok := graph.Documents[id]; ok {
229				return docToGQL(*doc), nil
230			}
231		}
232	
233		// File written but not yet in graph (e.g., missing DDx frontmatter).
234		return &Document{
235			ID:         cleaned,
236			Path:       cleaned,
237			DependsOn:  []string{},
238			Inputs:     []string{},
239			Dependents: []string{},
240		}, nil
