251		case "realign-specs", "run-checks":
252			return &WorkerDispatchResult{
253				ID:    "queued-worker-" + slug(kind),
254				State: queuedPlaceholderState,
255				Kind:  kind,
256			}, nil
257		default:
258			return nil, fmt.Errorf("unsupported worker kind %q", kind)
259		}
