262	// StartWorker is the resolver for the startWorker field.
263	//
264	// SD-024 Stage 1: the resolver flows through config.LoadAndResolve so the
265	// project's .ddx/config.yaml drives default harness/profile/effort/label
266	// values when the GraphQL input leaves them unset. Input fields are layered
267	// onto config as CLIOverrides — when present they win over the on-disk
268	// values. The resolved values are forwarded to ActionDispatcher (and ultimately
269	// to runWorker, which re-loads config to drive the loop's durable knobs like
270	// review_max_retries / no_progress_cooldown / heartbeat_interval). This
271	// closes the GraphQL bypass where hardcoded "smart"/"medium" defaults
272	// shadowed the on-disk config.
273	func (r *mutationResolver) StartWorker(ctx context.Context, input StartWorkerInput) (*WorkerDispatchResult, error) {
274		if r.Actions == nil {
275			return nil, fmt.Errorf("execute-loop worker dispatcher is not configured")
276		}
277		projectRoot := r.projectRoot(input.ProjectID)
278	
279		overrides := config.CLIOverrides{}
280		if input.Harness != nil {
281			overrides.Harness = strings.TrimSpace(*input.Harness)
282		}
283		if input.Profile != nil {
284			overrides.Profile = strings.TrimSpace(*input.Profile)
285		}
286		if input.Effort != nil {
287			overrides.Effort = strings.TrimSpace(*input.Effort)
288		}
289		rcfg, _ := config.LoadAndResolve(projectRoot, overrides)
290	
291		args := map[string]string{}
292		if v := rcfg.Harness(); v != "" {
293			args["harness"] = v
294		}
295		profile := rcfg.Profile()
296		if profile == "" {
297			profile = "smart"
298		}
299		args["profile"] = profile
300		effort := rcfg.Effort()
301		if effort == "" {
302			effort = "medium"
303		}
304		args["effort"] = effort
305		if input.LabelFilter != nil && strings.TrimSpace(*input.LabelFilter) != "" {
306			args["label_filter"] = strings.TrimSpace(*input.LabelFilter)
307		}
308		raw, err := json.Marshal(args)
309		if err != nil {
310			return nil, err
311		}
312		rawArgs := string(raw)
313		return r.Actions.DispatchWorker(ctx, "execute-loop", projectRoot, &rawArgs)
314	}
