356	// ComparisonDispatch is the resolver for the comparisonDispatch field.
357	func (r *mutationResolver) ComparisonDispatch(ctx context.Context, arms []*ComparisonArmInput) (*ComparisonDispatchResult, error) {
358		if len(arms) == 0 {
359			return nil, fmt.Errorf("comparison requires at least one arm")
360		}
361		for i, arm := range arms {
362			if arm == nil {
363				return nil, fmt.Errorf("comparison arm %d is required", i)
364			}
365			arm.Model = strings.TrimSpace(arm.Model)
366			arm.Prompt = strings.TrimSpace(arm.Prompt)
367			if arm.Model == "" {
368				return nil, fmt.Errorf("comparison arm %d model is required", i)
369			}
370			if arm.Prompt == "" {
371				return nil, fmt.Errorf("comparison arm %d prompt is required", i)
372			}
373			if arm.Harness != nil {
374				trimmed := strings.TrimSpace(*arm.Harness)
375				arm.Harness = &trimmed
376			}
377			if arm.Provider != nil {
378				trimmed := strings.TrimSpace(*arm.Provider)
379				arm.Provider = &trimmed
380			}
381		}
382	
383		id := newDispatchID("comparison")
384		record := comparisonDispatchRecord{
385			ID:        id,
386			State:     queuedPlaceholderState,
387			ArmCount:  len(arms),
388			Arms:      arms,
389			CreatedAt: time.Now().UTC(),
390		}
391		if err := writeJSONRecord(r.WorkingDir, "comparisons", id, record); err != nil {
392			return nil, err
393		}
394		return &ComparisonDispatchResult{
395			ID:       id,
396			State:    queuedPlaceholderState,
397			ArmCount: len(arms),
398		}, nil
399	}
